class LfuCache {
    struct Node {
        int val, freq;
        list<int>::iterator it;
    };

    int cap, minFreq;
    unordered_map<int, Node> keyMap;
    unordered_map<int, list<int>> freqMap;

public:
    LfuCache(int cacheCapacity) {
        cap = cacheCapacity;
        minFreq = 0;
    }

    int getValue(int key) {
        if (cap == 0 || !keyMap.count(key)) return -1;

        auto &node = keyMap[key];
        int f = node.freq;

        freqMap[f].erase(node.it);
        if (freqMap[f].empty()) {
            freqMap.erase(f);
            if (minFreq == f) minFreq++;
        }

        node.freq++;
        freqMap[node.freq].push_back(key);
        node.it = --freqMap[node.freq].end();

        return node.val;
    }

    void putValue(int key, int value) {
        if (cap == 0) return;

        if (keyMap.count(key)) {
            keyMap[key].val = value;
            getValue(key);
            return;
        }

        if ((int)keyMap.size() == cap) {
            int evictKey = freqMap[minFreq].front();
            freqMap[minFreq].pop_front();
            if (freqMap[minFreq].empty())
                freqMap.erase(minFreq);
            keyMap.erase(evictKey);
        }

        minFreq = 1;
        freqMap[1].push_back(key);
        keyMap[key] = {value, 1, --freqMap[1].end()};
    }
};

