typedef struct Node {
    int key;
    int value;
    int freq;
    struct Node *prev, *next;
} Node;

typedef struct {
    Node *head, *tail;
} DoublyList;

typedef struct {
    int capacity;
    int size;
    int minFreq;

    Node **keyMap;          // key -> Node*
    DoublyList **freqMap;   // freq -> DoublyList*
} LfuCache;


/* ---------- Doubly List helpers ---------- */

DoublyList* createList() {
    DoublyList* list = (DoublyList*)malloc(sizeof(DoublyList));
    list->head = list->tail = NULL;
    return list;
}

void addToTail(DoublyList* list, Node* node) {
    node->prev = list->tail;
    node->next = NULL;
    if (list->tail) list->tail->next = node;
    else list->head = node;
    list->tail = node;
}

void removeNode(DoublyList* list, Node* node) {
    if (node->prev) node->prev->next = node->next;
    else list->head = node->next;

    if (node->next) node->next->prev = node->prev;
    else list->tail = node->prev;
}

Node* removeHead(DoublyList* list) {
    if (!list->head) return NULL;
    Node* node = list->head;
    removeNode(list, node);
    return node;
}


/* ---------- LFU API ---------- */

LfuCache* createCache(int capacity) {
    LfuCache* cache = (LfuCache*)malloc(sizeof(LfuCache));
    cache->capacity = capacity;
    cache->size = 0;
    cache->minFreq = 0;

    cache->keyMap = (Node**)calloc(100001, sizeof(Node*));
    cache->freqMap = (DoublyList**)calloc(100001, sizeof(DoublyList*));

    return cache;
}

int getValue(LfuCache* cache, int key) {
    if (cache->capacity == 0 || cache->keyMap[key] == NULL)
        return -1;

    Node* node = cache->keyMap[key];
    int f = node->freq;

    removeNode(cache->freqMap[f], node);
    if (cache->freqMap[f]->head == NULL) {
        if (cache->minFreq == f)
            cache->minFreq++;
    }

    node->freq++;
    if (!cache->freqMap[node->freq])
        cache->freqMap[node->freq] = createList();

    addToTail(cache->freqMap[node->freq], node);
    return node->value;
}

void putValue(LfuCache* cache, int key, int value) {
    if (cache->capacity == 0)
        return;

    if (cache->keyMap[key]) {
        cache->keyMap[key]->value = value;
        getValue(cache, key);
        return;
    }

    if (cache->size == cache->capacity) {
        DoublyList* list = cache->freqMap[cache->minFreq];
        Node* evict = removeHead(list);
        cache->keyMap[evict->key] = NULL;
        free(evict);
        cache->size--;
    }

    Node* node = (Node*)malloc(sizeof(Node));
    node->key = key;
    node->value = value;
    node->freq = 1;

    if (!cache->freqMap[1])
        cache->freqMap[1] = createList();

    addToTail(cache->freqMap[1], node);
    cache->keyMap[key] = node;

    cache->minFreq = 1;
    cache->size++;
}

