class LfuCache {
    private static class Node {
        int val, freq;
        Node(int v, int f) { val = v; freq = f; }
    }

    private int cap, minFreq;
    private Map<Integer, Node> keyMap = new HashMap<>();
    private Map<Integer, LinkedHashSet<Integer>> freqMap = new HashMap<>();

    public LfuCache(int cacheCapacity) {
        cap = cacheCapacity;
        minFreq = 0;
    }

    public int getValue(int key) {
        if (cap == 0 || !keyMap.containsKey(key)) return -1;

        Node node = keyMap.get(key);
        int f = node.freq;

        freqMap.get(f).remove(key);
        if (freqMap.get(f).isEmpty()) {
            freqMap.remove(f);
            if (minFreq == f) minFreq++;
        }

        node.freq++;
        freqMap.computeIfAbsent(node.freq, k -> new LinkedHashSet<>()).add(key);

        return node.val;
    }

    public void putValue(int key, int value) {
        if (cap == 0) return;

        if (keyMap.containsKey(key)) {
            keyMap.get(key).val = value;
            getValue(key);
            return;
        }

        if (keyMap.size() == cap) {
            int evictKey = freqMap.get(minFreq).iterator().next();
            freqMap.get(minFreq).remove(evictKey);
            if (freqMap.get(minFreq).isEmpty())
                freqMap.remove(minFreq);
            keyMap.remove(evictKey);
        }

        minFreq = 1;
        keyMap.put(key, new Node(value, 1));
        freqMap.computeIfAbsent(1, k -> new LinkedHashSet<>()).add(key);
    }
}

