class LfuCache {
    constructor(capacity) {
        this.cap = capacity;
        this.minFreq = 0;
        this.keyMap = new Map();
        this.freqMap = new Map();
    }

    getValue(key) {
        if (this.cap === 0 || !this.keyMap.has(key)) return -1;

        let node = this.keyMap.get(key);
        let f = node.freq;

        this.freqMap.get(f).delete(key);
        if (this.freqMap.get(f).size === 0) {
            this.freqMap.delete(f);
            if (this.minFreq === f) this.minFreq++;
        }

        node.freq++;
        if (!this.freqMap.has(node.freq))
            this.freqMap.set(node.freq, new Set());
        this.freqMap.get(node.freq).add(key);

        return node.val;
    }

    putValue(key, value) {
        if (this.cap === 0) return;

        if (this.keyMap.has(key)) {
            this.keyMap.get(key).val = value;
            this.getValue(key);
            return;
        }

        if (this.keyMap.size === this.cap) {
            let evictKey = this.freqMap.get(this.minFreq).values().next().value;
            this.freqMap.get(this.minFreq).delete(evictKey);
            if (this.freqMap.get(this.minFreq).size === 0)
                this.freqMap.delete(this.minFreq);
            this.keyMap.delete(evictKey);
        }

        this.minFreq = 1;
        this.keyMap.set(key, { val: value, freq: 1 });
        if (!this.freqMap.has(1))
            this.freqMap.set(1, new Set());
        this.freqMap.get(1).add(key);
    }
}
